"use client";

import { useState } from "react";

export default function ContactForm() {
  const [loading, setLoading] = useState(false);

  return (
    <form
      className="space-y-4"
      onSubmit={async (e) => {
        e.preventDefault();
        setLoading(true);

        const form = e.currentTarget;
        const formData = new FormData(form);

        const payload = {
          "your-name": String(formData.get("your-name") || ""),
          "your-email": String(formData.get("your-email") || ""),
          "your-subject": String(formData.get("your-subject") || ""),
          "your-message": String(formData.get("your-message") || ""),
        };

        try {
          const res = await fetch("/api/contact-submit", {
            method: "POST",
            headers: {
              "Content-Type": "application/json",
            },
            body: JSON.stringify(payload),
          });

          const data = await res.json();
          if (!res.ok || !data?.ok) {
            alert("Failed to submit. Please try again.");
            return;
          }

          alert("Message sent successfully!");
          form.reset();
        } catch {
          alert("Failed to submit. Please try again.");
        } finally {
          setLoading(false);
        }
      }}
    >
      <input
        name="your-name"
        type="text"
        placeholder="Your Name"
        autoComplete="name"
        required
        className="w-full border border-gray-200 rounded-xl px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-400"
      />
      <input
        name="your-email"
        type="email"
        placeholder="Your Email"
        autoComplete="email"
        required
        className="w-full border border-gray-200 rounded-xl px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-400"
      />
      <input
        name="your-subject"
        type="text"
        placeholder="Subject"
        required
        className="w-full border border-gray-200 rounded-xl px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-400"
      />
      <textarea
        name="your-message"
        placeholder="Your Message"
        rows={5}
        className="w-full border border-gray-200 rounded-xl px-4 py-3 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-400 resize-none"
      />
      <button
        type="submit"
        disabled={loading}
        className="w-full bg-indigo-600 text-white py-3 rounded-xl font-semibold hover:bg-indigo-700 transition-colors disabled:opacity-60"
      >
        {loading ? "Sending..." : "Send Message"}
      </button>
    </form>
  );
}
